import { createContext, useContext, useRef, useState, type ReactNode } from "react";
import {
  closestCenter,
  DndContext,
  DragOverlay,
  PointerSensor,
  pointerWithin,
  useSensor,
  useSensors,
  type CollisionDetection,
  type DragEndEvent,
  type DragMoveEvent,
  type DragStartEvent,
} from "@dnd-kit/core";
import { FileVideoIcon, ImageIcon, MusicIcon, TypeIcon } from "@/lib/hugeicons";
import { useEditor, useProject } from "@mcut/react";
import {
  type AssetRef,
  type TrackId,
} from "@mcut/timeline";
import { useDropPreview, useEditorUI, type DropPreview } from "./editor-ui";
import {
  elementForAsset,
  elementForTextPreset,
  insertElementOnNewTrack,
  insertElementOnTrack,
  type TextPreset,
} from "./editor-actions";
import { collectSnapTargets, pointerToTimelineMs, snapClip, type SnapTarget } from "./timeline-snap";
import { formatDurationBadge } from "./format";

/** Payloads carried by dnd-kit drags. Track sorting is handled separately. */
export type EditorDragData =
  | { kind: "asset"; asset: AssetRef; thumb?: string }
  | { kind: "text-preset"; preset: TextPreset }
  | { kind: "track"; trackId: TrackId };

/** Data attached to timeline lane droppables. */
export interface LaneDropData {
  laneTrackId: string | "new-track";
}

const ActiveDragContext = createContext<EditorDragData | null>(null);

/** The payload currently being dragged (null when idle). */
export function useActiveDrag(): EditorDragData | null {
  return useContext(ActiveDragContext);
}

const SNAP_THRESHOLD_PX = 8;

function dragDurationMs(data: EditorDragData): number {
  if (data.kind === "asset") {
    return data.asset.kind === "image" ? 4000 : (data.asset.durationMs ?? 3000);
  }
  if (data.kind === "text-preset") return data.preset.durationMs;
  return 0;
}

function dragLabel(data: EditorDragData): string {
  if (data.kind === "asset") return data.asset.name ?? data.asset.kind;
  if (data.kind === "text-preset") return data.preset.name;
  return "";
}

function isLaneDropData(data: unknown): data is LaneDropData {
  return (
    typeof data === "object" &&
    data !== null &&
    "laneTrackId" in data &&
    typeof (data as LaneDropData).laneTrackId === "string"
  );
}

/** Lanes get pointer-precision; track sorting wants nearest-row. */
const collisionDetection: CollisionDetection = (args) => {
  const data = args.active.data.current as EditorDragData | undefined;
  if (data?.kind === "track") return closestCenter(args);
  const droppableContainers = args.droppableContainers.filter((container) => {
    const dropData = container.data.current;
    return isLaneDropData(dropData);
  });
  return pointerWithin({ ...args, droppableContainers });
};

function DragGhost({ data }: { data: EditorDragData }) {
  // Once the in-lane ghost is live, the floating card would only cover it —
  // the snapped ghost (with its own label/timecode) is the better feedback.
  const preview = useDropPreview();
  const Icon =
    data.kind === "text-preset"
      ? TypeIcon
      : data.kind === "asset" && data.asset.kind === "video"
        ? FileVideoIcon
        : data.kind === "asset" && data.asset.kind === "audio"
          ? MusicIcon
          : ImageIcon;
  const thumb = data.kind === "asset" ? data.thumb : undefined;
  if (preview) return null;
  return (
    <div className="pointer-events-none flex w-44 items-center gap-2 rounded-lg border bg-popover p-1.5 shadow-xl ring-1 ring-primary/40">
      <div className="flex size-9 shrink-0 items-center justify-center overflow-hidden rounded-md bg-muted">
        {thumb ? (
          // eslint-disable-next-line @next/next/no-img-element
          <img src={thumb} alt="" className="size-full object-cover" />
        ) : (
          <Icon className="size-4 text-muted-foreground" />
        )}
      </div>
      <div className="min-w-0 flex-1">
        <p className="truncate text-xs font-medium">{dragLabel(data)}</p>
        <p className="font-mono text-2xs text-muted-foreground">
          {formatDurationBadge(dragDurationMs(data))}
        </p>
      </div>
    </div>
  );
}

/**
 * One DndContext for the whole editor: media-bin assets and text presets
 * drag onto timeline lanes (with a snapped in-lane ghost), track rows sort
 * vertically. Clip move/trim stays on raw pointer events for ms precision.
 */
export function EditorDnd({
  children,
  onTrackSort,
}: {
  children: ReactNode;
  /** Called when a track row is dropped over another (sortable ids). */
  onTrackSort?: (activeTrackId: string, overTrackId: string) => void;
}) {
  const engine = useEditor();
  const project = useProject();
  const { pxPerMs, snapEnabled, editMode, setDropPreview, setSnapGuideMs } = useEditorUI();
  const [activeDrag, setActiveDrag] = useState<EditorDragData | null>(null);
  // Snap targets are stable for the whole drag (only the dragged payload
  // moves), so collect them once at drag start instead of per pointermove.
  const snapTargetsRef = useRef<SnapTarget[]>([]);
  // Coalesce drag moves to the frame rate: pointermove can fire at 120Hz+.
  const moveFrameRef = useRef<number | null>(null);
  const lastMoveRef = useRef<DragMoveEvent | null>(null);

  const sensors = useSensors(
    useSensor(PointerSensor, { activationConstraint: { distance: 6 } }),
  );

  const clear = () => {
    if (moveFrameRef.current !== null) {
      cancelAnimationFrame(moveFrameRef.current);
      moveFrameRef.current = null;
    }
    lastMoveRef.current = null;
    setActiveDrag(null);
    setDropPreview(null);
    setSnapGuideMs(null);
  };

  const previewFor = (event: DragMoveEvent): DropPreview | null => {
    const data = event.active.data.current as EditorDragData | undefined;
    if (!data || data.kind === "track") return null;
    const over = event.over;
    const laneData = over?.data.current as LaneDropData | undefined;
    if (!over || !laneData?.laneTrackId) return null;

    const activator = event.activatorEvent as PointerEvent;
    const pointerX = (activator.clientX ?? 0) + event.delta.x;
    const durationMs = dragDurationMs(data);
    const rawMs = pointerToTimelineMs(pointerX, over.rect, pxPerMs);
    const snapped = snapClip(rawMs, durationMs, snapTargetsRef.current, SNAP_THRESHOLD_PX / pxPerMs, {
      enabled: snapEnabled,
      fps: project.fps,
    });
    return {
      trackId: laneData.laneTrackId,
      startMs: Math.max(0, snapped.ms),
      durationMs,
      label: dragLabel(data),
    };
  };

  const handleDragStart = (event: DragStartEvent) => {
    snapTargetsRef.current = collectSnapTargets(project, engine.playback.state.currentTimeMs);
    setActiveDrag((event.active.data.current as EditorDragData) ?? null);
    setSnapGuideMs(null); // guide is implied by the ghost edges; keep UI quiet
  };

  const handleDragMove = (event: DragMoveEvent) => {
    const data = event.active.data.current as EditorDragData | undefined;
    if (!data || data.kind === "track") return;
    // Leading + trailing: apply the first move immediately, fold any burst
    // that follows into one update on the next frame.
    lastMoveRef.current = event;
    if (moveFrameRef.current !== null) return;
    setDropPreview(previewFor(event));
    moveFrameRef.current = requestAnimationFrame(() => {
      moveFrameRef.current = null;
      const last = lastMoveRef.current;
      if (last) setDropPreview(previewFor(last));
    });
  };

  const handleDragEnd = (event: DragEndEvent) => {
    const data = event.active.data.current as EditorDragData | undefined;
    try {
      if (data?.kind === "track") {
        const overId = event.over?.id;
        if (overId && overId !== event.active.id && onTrackSort) {
          onTrackSort(String(event.active.id), String(overId));
        }
        return;
      }
      const preview = previewFor(event);
      if (!data || !preview) return;
      const element =
        data.kind === "asset"
          ? elementForAsset(engine, data.asset)
          : elementForTextPreset(engine, data.preset);
      if (preview.trackId === "new-track") {
        insertElementOnNewTrack(engine, element, preview.startMs);
      } else {
        insertElementOnTrack(engine, preview.trackId as TrackId, element, preview.startMs, editMode);
      }
    } finally {
      clear();
    }
  };

  return (
    <DndContext
      id="mcut-editor-dnd"
      sensors={sensors}
      collisionDetection={collisionDetection}
      // Default measuring (once per drag) is enough: the "new track" lane is
      // always mounted, so rows never shift when a drag starts.
      onDragStart={handleDragStart}
      onDragMove={handleDragMove}
      onDragEnd={handleDragEnd}
      onDragCancel={clear}
    >
      <ActiveDragContext.Provider value={activeDrag}>
        {children}
        <DragOverlay dropAnimation={null}>
          {activeDrag && activeDrag.kind !== "track" ? <DragGhost data={activeDrag} /> : null}
        </DragOverlay>
      </ActiveDragContext.Provider>
    </DndContext>
  );
}

"use client";

import {
  createContext,
  useCallback,
  useContext,
  useEffect,
  useMemo,
  useRef,
  useState,
  useSyncExternalStore,
  type ReactNode,
} from "react";
import type { PreviewQuality } from "@mcut/react";
import { clamp } from "./math";

/** A live drop ghost while dragging media over the timeline. */
export interface DropPreview {
  /** Target track id, or "new-track" for the phantom top lane. */
  trackId: string;
  startMs: number;
  durationMs: number;
  label: string;
}

// ---------------------------------------------------------------------------
// Drag overlay stores
// ---------------------------------------------------------------------------
// Drop ghost and snap guide update on every pointermove during a drag. They
// live in tiny external stores (not React context state) so a drag move
// re-renders only the overlay components that subscribe via useDropPreview/
// useSnapGuideMs — never the whole editor tree.

interface OverlayStore<T> {
  get: () => T;
  set: (value: T) => void;
  subscribe: (listener: () => void) => () => void;
}

function createOverlayStore<T>(initial: T, equals: (a: T, b: T) => boolean): OverlayStore<T> {
  let value = initial;
  const listeners = new Set<() => void>();
  return {
    get: () => value,
    set: (next: T) => {
      if (equals(value, next)) return;
      value = next;
      for (const listener of listeners) listener();
    },
    subscribe: (listener: () => void) => {
      listeners.add(listener);
      return () => listeners.delete(listener);
    },
  };
}

function dropPreviewEquals(a: DropPreview | null, b: DropPreview | null): boolean {
  if (a === b) return true;
  if (!a || !b) return false;
  return (
    a.trackId === b.trackId &&
    a.startMs === b.startMs &&
    a.durationMs === b.durationMs &&
    a.label === b.label
  );
}

interface DragOverlayStores {
  dropPreview: OverlayStore<DropPreview | null>;
  snapGuide: OverlayStore<number | null>;
}

const DragOverlayContext = createContext<DragOverlayStores | null>(null);

function useDragOverlayStores(): DragOverlayStores {
  const stores = useContext(DragOverlayContext);
  if (!stores) throw new Error("drag overlay hooks must be used inside <EditorUIProvider>");
  return stores;
}

/** The live drop ghost, or null when no media drag is over the timeline. */
export function useDropPreview(): DropPreview | null {
  const { dropPreview } = useDragOverlayStores();
  return useSyncExternalStore(dropPreview.subscribe, dropPreview.get, () => null);
}

/** The snap guide line (timeline ms), or null when nothing is snapping. */
export function useSnapGuideMs(): number | null {
  const { snapGuide } = useDragOverlayStores();
  return useSyncExternalStore(snapGuide.subscribe, snapGuide.get, () => null);
}

export type EditorTheme = "dark" | "light";

/**
 * Editing modes are VIEWS, not document state: they re-emphasize affordances
 * (multicam = layout bank + 1–9 switching) over the same project.
 */
export type EditorMode = "edit" | "multicam";

/**
 * Timeline pointer tools (Premiere's tool palette): select is the default
 * move/trim tool; ripple/roll change what the trim handles do; slip/slide
 * change what dragging the clip body does.
 */
export type TimelineTool = "select" | "ripple" | "roll" | "slip" | "slide";

/**
 * Placement mode for inserts and drops (Kdenlive's taxonomy): normal rejects
 * collisions, overwrite clears the landing range, insert ripples everything
 * after the point to the right.
 */
export type TimelineEditMode = "normal" | "overwrite" | "insert";

export interface EditorUIValue {
  /** Editor color theme (warm grey light/dark; tokens in globals.css). */
  theme: EditorTheme;
  setTheme: (value: EditorTheme) => void;
  /** Current editing mode (session-scoped; not persisted). */
  mode: EditorMode;
  setMode: (value: EditorMode) => void;
  /** Layout whose slots are being edited on the canvas (multicam mode). */
  editingLayoutId: string | null;
  setEditingLayoutId: (value: string | null) => void;
  /**
   * Slot edit state: index of the slot (within the editing layout) whose
   * properties the inspector shows. Shared so the canvas overlay and the
   * properties panel select and style the same slot.
   */
  editingSlotIndex: number | null;
  setEditingSlotIndex: (value: number | null) => void;
  /** Text element being edited INLINE on the canvas (double-click to enter). */
  editingTextId: string | null;
  setEditingTextId: (value: string | null) => void;
  /** Timeline zoom. */
  pxPerMs: number;
  setPxPerMs: (value: number) => void;
  /** Zoom keeping `anchorMs` under the same screen x (used by ⌘+wheel). */
  zoomBy: (factor: number, anchorMs?: number) => void;
  snapEnabled: boolean;
  setSnapEnabled: (value: boolean) => void;
  /** Active timeline pointer tool (session-scoped). */
  timelineTool: TimelineTool;
  setTimelineTool: (value: TimelineTool) => void;
  /** Placement mode for inserts/drops (session-scoped). */
  editMode: TimelineEditMode;
  setEditMode: (value: TimelineEditMode) => void;
  /** Drop a dissolve when a dragged clip is pushed flush against a neighbor. */
  autoCrossfade: boolean;
  setAutoCrossfade: (value: boolean) => void;
  /** Preview raster resolution ('auto' fits the pane; numbers cap the short side). */
  previewQuality: PreviewQuality;
  setPreviewQuality: (value: PreviewQuality) => void;
  /** Publish the drop ghost (read it via useDropPreview — it's not in this context). */
  setDropPreview: (value: DropPreview | null) => void;
  /** The timeline's horizontal scroll container (for zoom anchoring/auto-scroll). */
  timelineScrollRef: React.RefObject<HTMLDivElement | null>;
  /** Publish the snap guide line (read it via useSnapGuideMs). */
  setSnapGuideMs: (value: number | null) => void;
}

export const MIN_PX_PER_MS = 0.004;
export const MAX_PX_PER_MS = 0.6;
/** Left header gutter width inside the timeline, px. */
export const TIMELINE_HEADER_WIDTH = 288;

const EditorUIContext = createContext<EditorUIValue | null>(null);

const PREFS_KEY = "mcut:ui";

function loadPrefs(): {
  pxPerMs?: number;
  snapEnabled?: boolean;
  autoCrossfade?: boolean;
  theme?: EditorTheme;
  previewQuality?: PreviewQuality;
} {
  if (typeof window === "undefined") return {};
  try {
    return JSON.parse(window.localStorage.getItem(PREFS_KEY) ?? "{}");
  } catch {
    return {};
  }
}

function isPreviewQuality(value: unknown): value is PreviewQuality {
  return value === "auto" || value === "full" || (typeof value === "number" && value > 0);
}

export function EditorUIProvider({ children }: { children: ReactNode }) {
  const [pxPerMs, setPxPerMsState] = useState(0.05);
  const [snapEnabled, setSnapEnabledState] = useState(true);
  const [timelineTool, setTimelineTool] = useState<TimelineTool>("select");
  const [editMode, setEditMode] = useState<TimelineEditMode>("normal");
  const [autoCrossfade, setAutoCrossfadeState] = useState(false);
  const [previewQuality, setPreviewQualityState] = useState<PreviewQuality>("auto");
  const [theme, setThemeState] = useState<EditorTheme>("dark");
  const [mode, setModeState] = useState<EditorMode>("edit");
  const [editingLayoutId, setEditingLayoutIdState] = useState<string | null>(null);
  const [editingSlotIndex, setEditingSlotIndex] = useState<number | null>(null);
  const [editingTextId, setEditingTextId] = useState<string | null>(null);
  const setEditingLayoutId = useCallback((value: string | null) => {
    setEditingLayoutIdState(value);
    setEditingSlotIndex(null); // slot selection is scoped to one layout
  }, []);
  const setMode = useCallback((value: EditorMode) => {
    setModeState(value);
    // Leaving a mode always exits slot editing.
    setEditingLayoutIdState(null);
    setEditingSlotIndex(null);
    setEditingTextId(null);
  }, []);
  const [overlayStores] = useState<DragOverlayStores>(() => ({
    dropPreview: createOverlayStore<DropPreview | null>(null, dropPreviewEquals),
    snapGuide: createOverlayStore<number | null>(null, Object.is),
  }));
  const setDropPreview = useCallback(
    (value: DropPreview | null) => overlayStores.dropPreview.set(value),
    [overlayStores],
  );
  const setSnapGuideMs = useCallback(
    (value: number | null) => overlayStores.snapGuide.set(value),
    [overlayStores],
  );
  const timelineScrollRef = useRef<HTMLDivElement | null>(null);

  useEffect(() => {
    // Apply persisted prefs after hydration (a lazy initializer would make
    // the server and client first paints disagree).
    const timer = setTimeout(() => {
      const prefs = loadPrefs();
      if (prefs.pxPerMs) setPxPerMsState(clampZoom(prefs.pxPerMs));
      if (prefs.snapEnabled !== undefined) setSnapEnabledState(prefs.snapEnabled);
      if (prefs.autoCrossfade !== undefined) setAutoCrossfadeState(prefs.autoCrossfade);
      if (isPreviewQuality(prefs.previewQuality)) setPreviewQualityState(prefs.previewQuality);
      if (prefs.theme === "light" || prefs.theme === "dark") setThemeState(prefs.theme);
    }, 0);
    return () => clearTimeout(timer);
  }, []);

  const persist = (patch: Record<string, unknown>) => {
    try {
      window.localStorage.setItem(PREFS_KEY, JSON.stringify({ ...loadPrefs(), ...patch }));
    } catch {
      // Private mode: prefs just don't persist.
    }
  };

  const setPxPerMs = useCallback((value: number) => {
    const clamped = clampZoom(value);
    setPxPerMsState(clamped);
    persist({ pxPerMs: clamped });
  }, []);

  const setTheme = useCallback((value: EditorTheme) => {
    setThemeState(value);
    persist({ theme: value });
  }, []);

  const setSnapEnabled = useCallback((value: boolean) => {
    setSnapEnabledState(value);
    persist({ snapEnabled: value });
  }, []);

  const setAutoCrossfade = useCallback((value: boolean) => {
    setAutoCrossfadeState(value);
    persist({ autoCrossfade: value });
  }, []);

  const setPreviewQuality = useCallback((value: PreviewQuality) => {
    setPreviewQualityState(value);
    persist({ previewQuality: value });
  }, []);

  const zoomBy = useCallback(
    (factor: number, anchorMs?: number) => {
      setPxPerMsState((previous) => {
        const next = clampZoom(previous * factor);
        const scroller = timelineScrollRef.current;
        if (scroller && anchorMs !== undefined) {
          // Keep anchorMs under the same screen x after the zoom.
          const anchorX = anchorMs * previous - scroller.scrollLeft;
          requestAnimationFrame(() => {
            scroller.scrollLeft = anchorMs * next - anchorX;
          });
        }
        persist({ pxPerMs: next });
        return next;
      });
    },
    [],
  );

  // Memoized so a provider re-render doesn't re-render every consumer; only
  // actual value changes do.
  const value = useMemo<EditorUIValue>(
    () => ({
      theme,
      setTheme,
      mode,
      setMode,
      editingLayoutId,
      setEditingLayoutId,
      editingSlotIndex,
      setEditingSlotIndex,
      editingTextId,
      setEditingTextId,
      pxPerMs,
      setPxPerMs,
      zoomBy,
      snapEnabled,
      setSnapEnabled,
      timelineTool,
      setTimelineTool,
      editMode,
      setEditMode,
      autoCrossfade,
      setAutoCrossfade,
      previewQuality,
      setPreviewQuality,
      setDropPreview,
      timelineScrollRef,
      setSnapGuideMs,
    }),
    [
      theme,
      setTheme,
      mode,
      setMode,
      editingLayoutId,
      setEditingLayoutId,
      editingSlotIndex,
      editingTextId,
      pxPerMs,
      setPxPerMs,
      zoomBy,
      snapEnabled,
      setSnapEnabled,
      timelineTool,
      editMode,
      autoCrossfade,
      setAutoCrossfade,
      previewQuality,
      setPreviewQuality,
      setDropPreview,
      setSnapGuideMs,
    ],
  );

  return (
    <EditorUIContext.Provider value={value}>
      <DragOverlayContext.Provider value={overlayStores}>
        {children}
      </DragOverlayContext.Provider>
    </EditorUIContext.Provider>
  );
}

function clampZoom(value: number): number {
  return clamp(value, MIN_PX_PER_MS, MAX_PX_PER_MS);
}

export function useEditorUI(): EditorUIValue {
  const context = useContext(EditorUIContext);
  if (!context) throw new Error("useEditorUI must be used inside <EditorUIProvider>");
  return context;
}

import {
  collectSnapTargets as collectTimelineSnapTargets,
  type Project,
  type SnapTarget,
} from "@mcut/timeline";

// The snap engine itself (targets, nearest-target search, frame fallback)
// lives in @mcut/timeline so every gesture and any host app agree on policy;
// this module keeps the app-shaped entry points.
export { snapClip, snapTime } from "@mcut/timeline";
export type { SnapClipResult, SnapOptions, SnapResult, SnapTarget } from "@mcut/timeline";

/**
 * Magnetic snap targets: timeline zero, the playhead, markers, and every
 * clip edge (except the elements being dragged). Sorted by time.
 */
export function collectSnapTargets(
  project: Project,
  playheadMs: number,
  excludeElementIds: ReadonlySet<string> = new Set(),
): SnapTarget[] {
  return collectTimelineSnapTargets(project, { playheadMs, excludeElementIds });
}

/** Convert a pointer clientX into timeline ms for a lane element. */
export function pointerToTimelineMs(
  clientX: number,
  laneRect: { left: number },
  pxPerMs: number,
): number {
  return Math.max(0, Math.round((clientX - laneRect.left) / pxPerMs));
}

/** 90500 → "1:30.5" (minutes:seconds.tenths). */
export function formatTimecode(ms: number): string {
  const total = Math.max(0, ms);
  const minutes = Math.floor(total / 60_000);
  const seconds = Math.floor((total % 60_000) / 1000);
  const tenths = Math.floor((total % 1000) / 100);
  return `${minutes}:${String(seconds).padStart(2, "0")}.${tenths}`;
}

/** Ruler label: 90000 → "1:30". */
export function formatRulerLabel(ms: number): string {
  const minutes = Math.floor(ms / 60_000);
  const seconds = Math.round((ms % 60_000) / 1000);
  return `${minutes}:${String(seconds).padStart(2, "0")}`;
}

/** 90500 → "1:31" rounded duration for badges. */
export function formatDurationBadge(ms: number): string {
  return formatRulerLabel(Math.round(ms / 1000) * 1000);
}

